$xl = New-Object -ComObject Excel.Application
$xl.Visible = $false; $xl.DisplayAlerts = $false
try {
  $wb = $xl.Workbooks.Add(); $ws = $wb.Worksheets.Item(1); $ws.Name = "ИКТ"
  $cols = @("№","РО","Тема занятия (через действие)","Всего","Теор.","Лаб.-пр.","Инд.","СРСП","СРС, ч","Тип занятия","Тема СРС (самостоятельная работа)","Связь с ПМ")
  $nc = $cols.Count
  $ws.Cells.Item(1,1).Value2 = $titleText
  $ws.Range($ws.Cells.Item(1,1), $ws.Cells.Item(1,$nc)).Merge()
  $ws.Cells.Item(1,1).Font.Bold = $true; $ws.Cells.Item(1,1).Font.Size = 12
  for($c=0;$c -lt $nc;$c++){ $ws.Cells.Item(2,$c+1).Value2 = $cols[$c] }
  $hdr = $ws.Range($ws.Cells.Item(2,1), $ws.Cells.Item(2,$nc))
  $hdr.Font.Bold = $true; $hdr.Interior.Color = 15983833; $hdr.HorizontalAlignment = -4108; $hdr.VerticalAlignment = -4108; $hdr.WrapText = $true

  # авто-итоги: суммируем idx 3..8 (Всего,Т,ЛП,Инд,Сп,СРС) по строкам данных
  $sum = @(0,0,0,0,0,0)
  foreach($d in $rows){ if(([string]$d[0]) -ne "__HDR__"){ for($j=0;$j -lt 6;$j++){ $vv=$d[$j+3]; if("$vv" -match '^\d+(\.\d+)?$'){ $sum[$j]+=[double]$vv } } } }

  $startRow = 3; $ndr = $rows.Count; $hdrRowsX = @(); $rw = $startRow
  for($i=0;$i -lt $ndr;$i++){
    $d = $rows[$i]; $tag = [string]$d[0]
    if($tag -eq "__HDR__"){ $ws.Cells.Item($rw,1).Value2 = [string]$d[1]; $hdrRowsX += $rw }
    else { for($c=0;$c -lt $nc;$c++){ $v="$($d[$c])"; if($v.Trim().Length -gt 0){ $ws.Cells.Item($rw,$c+1).Value2 = $v } } }
    $rw++
  }
  # строка ВСЕГО
  $totalRowX = $rw
  $ws.Cells.Item($rw,3).Value2 = "ВСЕГО"
  for($j=0;$j -lt 6;$j++){ $ws.Cells.Item($rw,$j+4).Value2 = "$([int]$sum[$j])" }
  $last = $rw

  for($col=4;$col -le 9;$col++){ $rngN = $ws.Range($ws.Cells.Item($startRow,$col), $ws.Cells.Item($last,$col)); [void]$rngN.TextToColumns($ws.Cells.Item($startRow,$col), 1) }
  foreach($hr in $hdrRowsX){ $ws.Range($ws.Cells.Item($hr,1), $ws.Cells.Item($hr,$nc)).Merge(); $rr = $ws.Range($ws.Cells.Item($hr,1), $ws.Cells.Item($hr,$nc)); $rr.Font.Bold = $true; $rr.Interior.Color = 14215660 }
  $tr2 = $ws.Range($ws.Cells.Item($totalRowX,1), $ws.Cells.Item($totalRowX,$nc)); $tr2.Font.Bold = $true; $tr2.Interior.Color = 13684944

  $all = $ws.Range($ws.Cells.Item(2,1), $ws.Cells.Item($last,$nc))
  for($b=7;$b -le 12;$b++){ $all.Borders.Item($b).LineStyle = 1; $all.Borders.Item($b).Weight = 2 }
  $all.VerticalAlignment = -4160
  $ws.Columns.Item(3).WrapText = $true; $ws.Columns.Item(10).WrapText = $true; $ws.Columns.Item(11).WrapText = $true; $ws.Columns.Item(12).WrapText = $true
  $w = @(4,5,50,6,6,7,5,6,6,16,42,20)
  for($c=1;$c -le 12;$c++){ $ws.Columns.Item($c).ColumnWidth = $w[$c-1] }
  $ws.Range($ws.Cells.Item(2,4), $ws.Cells.Item($last,9)).HorizontalAlignment = -4108
  $n1=$last+2; $ws.Cells.Item($n1,1).Value2="Этика и ответственное использование ИИ — сквозной компонент всех тем РО 2.3: человекоцентричный подход, критическая оценка результатов, соблюдение законодательства РК."; $ws.Range($ws.Cells.Item($n1,1),$ws.Cells.Item($n1,$nc)).Merge(); $ws.Cells.Item($n1,1).Font.Italic=$true
  $n2=$last+3; $ws.Cells.Item($n2,1).Value2="Оценивание (AI-устойчивое): приоритет — устная защита проектов и практических работ; письменные работы дополняются устной защитой/демонстрацией."; $ws.Range($ws.Cells.Item($n2,1),$ws.Cells.Item($n2,$nc)).Merge(); $ws.Cells.Item($n2,1).Font.Italic=$true
  $ws.Application.ActiveWindow.SplitRow = 2; $ws.Application.ActiveWindow.FreezePanes = $true

  $wb.SaveAs($out, 51)
  Write-Output ("СОХРАНЕНО: " + $out)
  Write-Output ("ИТОГИ: Всего=$([int]$sum[0]) Теор=$([int]$sum[1]) Лаб=$([int]$sum[2]) Инд=$([int]$sum[3]) СРСП=$([int]$sum[4]) СРС=$([int]$sum[5])")
} finally { $xl.Quit(); [System.Runtime.Interopservices.Marshal]::ReleaseComObject($xl) | Out-Null }
